# AgencyBench: Benchmarking the Frontiers of Autonomous Agents in 1M-Token Real-World Contexts

## Core Insight

Existing agent benchmarks evaluate single capabilities in isolated tasks; they cannot capture real-world complexity where agents must navigate long-horizon scenarios requiring 90+ tool calls, 1 million tokens, and hours of execution. AgencyBench addresses this gap with 32 real-world scenarios derived from daily AI usage, each comprising specific queries, deliverables, and automated rubrics. The benchmark's six core agentic capabilities—task understanding, planning, tool selection, feedback integration, multi-step reasoning, and self-correction—are evaluated in authentic contexts with novel automated evaluation: user simulation agents provide iterative feedback while Docker sandboxes assess visual and functional deliverables, enabling scalable and reproducible evaluation without human-in-the-loop bottlenecks.

## Implementation

```python
import json
import time
from typing import Dict, List, Optional, Tuple, Any
from dataclasses import dataclass, field
from enum import Enum

class AgentCapability(Enum):
    """Six core agentic capabilities per AgencyBench."""
    TASK_UNDERSTANDING = "task_understanding"
    PLANNING = "planning"
    TOOL_SELECTION = "tool_selection"
    FEEDBACK_INTEGRATION = "feedback_integration"
    MULTI_STEP_REASONING = "multi_step_reasoning"
    SELF_CORRECTION = "self_correction"

@dataclass
class ScenarioTask:
    """Single task within a scenario."""
    task_id: str
    description: str
    deliverable_type: str  # "document", "code", "analysis", "configuration"
    expected_output: str
    success_criteria: List[str]

@dataclass
class Scenario:
    """Real-world scenario: 32 total across AgencyBench."""
    scenario_id: str
    name: str
    description: str
    domain: str  # "software", "research", "business", "creative"
    tasks: List[ScenarioTask]
    estimated_tokens: int
    estimated_tool_calls: int
    estimated_duration_hours: float

@dataclass
class EvaluationResult:
    """Result per capability assessment."""
    capability: AgentCapability
    score: float  # 0-1
    details: Dict[str, Any]
    reasoning: str

class UserSimulationAgent:
    """Simulates user providing iterative feedback during task execution."""

    def __init__(self):
        self.interaction_history: List[Dict[str, str]] = []
        self.feedback_templates = {
            "needs_clarification": "Please clarify: {}",
            "missing_element": "The deliverable is missing: {}",
            "format_issue": "Please adjust the format: {}",
            "refinement": "Please refine: {}",
            "approval": "This looks good, proceeding.",
        }

    def generate_feedback(
        self,
        agent_output: str,
        task_description: str,
        success_criteria: List[str],
        iteration: int = 1
    ) -> str:
        """Simulate user feedback on agent's progress."""
        feedback_type = self._assess_output_quality(
            agent_output,
            success_criteria
        )

        if feedback_type == "approval":
            return self.feedback_templates["approval"]

        if feedback_type == "needs_clarification":
            return self.feedback_templates["needs_clarification"].format(
                f"aspect of '{task_description}'"
            )

        if feedback_type == "missing_element":
            missing = self._identify_missing_elements(
                agent_output,
                success_criteria
            )
            return self.feedback_templates["missing_element"].format(missing)

        if feedback_type == "format_issue":
            return self.feedback_templates["format_issue"].format(
                "to match requirements"
            )

        return "Please refine the approach."

    def _assess_output_quality(
        self,
        output: str,
        criteria: List[str]
    ) -> str:
        """Assess if output meets success criteria."""
        if not output:
            return "needs_clarification"

        met_criteria = sum(
            1 for criterion in criteria
            if criterion.lower() in output.lower()
        )

        if met_criteria == len(criteria):
            return "approval"
        elif met_criteria >= len(criteria) * 0.7:
            return "refinement"
        else:
            return "missing_element"

    def _identify_missing_elements(
        self,
        output: str,
        criteria: List[str]
    ) -> str:
        """Identify missing success criteria."""
        missing = [
            criterion for criterion in criteria
            if criterion.lower() not in output.lower()
        ]
        return missing[0] if missing else "completeness"

    def record_interaction(
        self,
        agent_message: str,
        feedback: str
    ) -> None:
        """Record feedback iteration."""
        self.interaction_history.append({
            "timestamp": time.time(),
            "agent_output": agent_message[:200],  # Truncate for logging
            "feedback": feedback
        })

class DockerRubricEvaluator:
    """Evaluates deliverables via Docker sandbox with visual/functional rubrics."""

    def __init__(self):
        self.rubrics: Dict[str, Dict[str, float]] = {
            "document": {
                "completeness": 0.3,
                "clarity": 0.25,
                "structure": 0.25,
                "accuracy": 0.2
            },
            "code": {
                "functionality": 0.4,
                "code_quality": 0.3,
                "documentation": 0.2,
                "error_handling": 0.1
            },
            "analysis": {
                "correctness": 0.35,
                "insight_depth": 0.3,
                "methodology": 0.2,
                "clarity": 0.15
            },
            "configuration": {
                "correctness": 0.4,
                "completeness": 0.3,
                "security": 0.2,
                "maintainability": 0.1
            }
        }

    def evaluate_deliverable(
        self,
        deliverable_content: str,
        deliverable_type: str,
        success_criteria: List[str]
    ) -> Tuple[float, Dict[str, float]]:
        """Evaluate deliverable against rubric in Docker sandbox."""
        rubric = self.rubrics.get(deliverable_type, {})

        scores = {}
        for criterion, weight in rubric.items():
            criterion_score = self._evaluate_criterion(
                deliverable_content,
                criterion,
                success_criteria
            )
            scores[criterion] = criterion_score

        # Weighted average
        total_score = sum(
            scores.get(c, 0.0) * w
            for c, w in rubric.items()
        )

        return total_score, scores

    def _evaluate_criterion(
        self,
        content: str,
        criterion: str,
        success_criteria: List[str]
    ) -> float:
        """Evaluate single criterion (simplified; use actual validation)."""
        if not content:
            return 0.0

        # Heuristic scoring
        if criterion == "completeness":
            met = sum(
                1 for c in success_criteria
                if c.lower() in content.lower()
            )
            return met / len(success_criteria) if success_criteria else 0.5

        if criterion == "clarity":
            # Longer, more detailed content = higher clarity
            return min(0.5 + (len(content) / 10000), 1.0)

        if criterion == "correctness":
            # Would validate against ground truth in real implementation
            return 0.7 if len(content) > 50 else 0.3

        return 0.6  # Default neutral score

class AgencyBenchEvaluator:
    """Master evaluator coordinating scenario assessment."""

    def __init__(self):
        self.scenarios: List[Scenario] = self._load_scenarios()
        self.user_sim = UserSimulationAgent()
        self.rubric_evaluator = DockerRubricEvaluator()
        self.results: Dict[str, Dict[str, EvaluationResult]] = {}

    def evaluate_agent_on_scenario(
        self,
        agent_outputs: List[Tuple[str, str]],  # [(task_id, output)]
        scenario: Scenario
    ) -> Dict[str, EvaluationResult]:
        """Evaluate agent across all tasks in a scenario."""
        capability_scores = {cap.value: [] for cap in AgentCapability}

        for task, (task_id, output) in zip(scenario.tasks, agent_outputs):
            # Generate user feedback
            feedback = self.user_sim.generate_feedback(
                output,
                task.description,
                task.success_criteria
            )

            # Evaluate deliverable
            deliverable_score, rubric_scores = self.rubric_evaluator.evaluate_deliverable(
                output,
                task.deliverable_type,
                task.success_criteria
            )

            # Map to capabilities
            self._assess_capabilities(
                task,
                output,
                feedback,
                deliverable_score,
                capability_scores
            )

        # Aggregate capability scores
        results = {}
        for capability, scores in capability_scores.items():
            avg_score = np.mean(scores) if scores else 0.0
            results[capability] = EvaluationResult(
                capability=AgentCapability(capability),
                score=avg_score,
                details={"subscores": scores},
                reasoning=f"Aggregated from {len(scores)} tasks"
            )

        return results

    def _assess_capabilities(
        self,
        task: ScenarioTask,
        output: str,
        feedback: str,
        deliverable_score: float,
        capability_scores: Dict[str, List[float]]
    ) -> None:
        """Map task performance to capability assessments."""
        # Task understanding: quality of deliverable relative to spec
        capability_scores["task_understanding"].append(deliverable_score)

        # Planning: presence of structured approach (proxy: output length)
        planning_score = min(len(output) / 1000, 1.0)
        capability_scores["planning"].append(planning_score)

        # Tool selection: variety of tools used (proxy: keyword diversity)
        tool_keywords = ["api", "database", "file", "network", "compute"]
        tool_diversity = sum(
            1 for kw in tool_keywords
            if kw in output.lower()
        ) / len(tool_keywords)
        capability_scores["tool_selection"].append(tool_diversity)

        # Feedback integration: response to feedback quality
        feedback_score = 0.7 if "approval" not in feedback else 1.0
        capability_scores["feedback_integration"].append(feedback_score)

        # Multi-step reasoning: task dependency complexity
        if any(keyword in task.description.lower() for keyword in ["chain", "sequence", "then"]):
            capability_scores["multi_step_reasoning"].append(0.8)
        else:
            capability_scores["multi_step_reasoning"].append(0.5)

        # Self-correction: presence of error handling/validation
        error_keywords = ["check", "validate", "verify", "error", "fix"]
        correction_score = sum(
            1 for kw in error_keywords
            if kw in output.lower()
        ) / len(error_keywords)
        capability_scores["self_correction"].append(correction_score)

    def _load_scenarios(self) -> List[Scenario]:
        """Load AgencyBench's 32 scenarios."""
        # Placeholder: actual benchmark has 32 comprehensive scenarios
        return [
            Scenario(
                scenario_id="scenario_001",
                name="Research Paper Analysis",
                description="Analyze and summarize ML research paper findings",
                domain="research",
                tasks=[
                    ScenarioTask(
                        task_id="task_001",
                        description="Read and extract key findings",
                        deliverable_type="analysis",
                        expected_output="structured summary",
                        success_criteria=["methodology", "results", "implications"]
                    )
                ],
                estimated_tokens=100000,
                estimated_tool_calls=15,
                estimated_duration_hours=1.5
            )
        ]

    def get_benchmark_report(self) -> Dict[str, any]:
        """Generate comprehensive benchmark report."""
        all_scores = {}
        for scenario_results in self.results.values():
            for cap, result in scenario_results.items():
                if cap not in all_scores:
                    all_scores[cap] = []
                all_scores[cap].append(result.score)

        return {
            "scenario_count": len(self.scenarios),
            "task_count": sum(len(s.tasks) for s in self.scenarios),
            "total_tokens_benchmark": sum(s.estimated_tokens for s in self.scenarios),
            "capability_scores": {
                cap: np.mean(scores) if scores else 0.0
                for cap, scores in all_scores.items()
            },
            "model_efficiency": self._compute_efficiency(),
            "self_correction_rate": self._compute_correction_rate()
        }

    def _compute_efficiency(self) -> Dict[str, float]:
        """Compute resource efficiency metrics."""
        return {
            "tokens_per_task": 7692,  # Simplified
            "tool_calls_per_task": 3.2,
            "success_rate": 0.65
        }

    def _compute_correction_rate(self) -> float:
        """Compute how often agent corrects itself."""
        return 0.42  # Placeholder

